/**
 * Footer component - Dynamic footer driven by site settings
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import Link from 'next/link';
import { useParams } from 'next/navigation';
import { useSiteSettings } from '@/hooks/useSiteSettings';
import { Twitter, Linkedin, Facebook, Instagram, Youtube, Github, Mail, Phone, MapPin } from 'lucide-react';

const SOCIAL_ICONS = {
  twitter: Twitter,
  linkedin: Linkedin,
  facebook: Facebook,
  instagram: Instagram,
  youtube: Youtube,
  github: Github,
};

export function Footer() {
  const { settings } = useSiteSettings();
  const params = useParams();
  const lang = params?.lang || 'en';

  const footer = settings.footer;
  const style = footer?.style || {};
  const bottomBar = footer?.bottomBar;

  const copyrightText = (bottomBar?.copyrightText || '© {year} English Website. All rights reserved.')
    .replace('{year}', new Date().getFullYear().toString());

  const inlineStyle: React.CSSProperties = {
    ...(style.backgroundColor ? { backgroundColor: style.backgroundColor } : {}),
    ...(style.textColor ? { color: style.textColor } : {}),
  };

  const borderStyle: React.CSSProperties = style.borderColor
    ? { borderColor: style.borderColor }
    : {};

  return (
    <footer
      className={`bg-slate-100 dark:bg-neutral-900 text-slate-600 dark:text-neutral-300 border-t border-slate-200 dark:border-neutral-800`}
      style={inlineStyle}
      role="contentinfo"
    >
      <div className={`max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 ${style.padding || 'py-12'}`}>
        <div className={`grid gap-8 ${footer?.columns?.length ? `md:grid-cols-${Math.min(footer.columns.length + 1, 4)}` : 'md:grid-cols-3'}`}>
          {/* Brand Column */}
          <div>
            <h3
              className="font-semibold mb-3 text-slate-900 dark:text-white"
              style={style.linkColor ? { color: style.linkColor } : {}}
            >
              {footer?.companyName || 'English Website'}
            </h3>
            {footer?.tagline && (
              <p className="text-sm font-medium mb-2 opacity-80">{footer.tagline}</p>
            )}
            {footer?.description && (
              <p className="text-sm leading-relaxed">{footer.description}</p>
            )}
            {/* Contact Info */}
            {footer?.contactInfo?.show && (
              <div className="mt-4 space-y-2">
                {footer.contactInfo.phone && (
                  <a
                    href={`tel:${footer.contactInfo.phone}`}
                    className="flex items-center gap-2 text-sm hover:text-slate-900 dark:hover:text-white transition-colors"
                  >
                    <Phone className="h-3.5 w-3.5 shrink-0" />
                    {footer.contactInfo.phone}
                  </a>
                )}
                {footer.contactInfo.email && (
                  <a
                    href={`mailto:${footer.contactInfo.email}`}
                    className="flex items-center gap-2 text-sm hover:text-slate-900 dark:hover:text-white transition-colors"
                  >
                    <Mail className="h-3.5 w-3.5 shrink-0" />
                    {footer.contactInfo.email}
                  </a>
                )}
                {footer.contactInfo.address && (
                  <p className="flex items-start gap-2 text-sm">
                    <MapPin className="h-3.5 w-3.5 shrink-0 mt-0.5" />
                    {footer.contactInfo.address}
                  </p>
                )}
              </div>
            )}
          </div>

          {/* Dynamic Link Columns */}
          {(footer?.columns || []).map((col) => (
            <div key={col.id}>
              <h4
                className="font-medium mb-4 text-slate-900 dark:text-white"
                style={style.linkColor ? { color: style.linkColor } : {}}
              >
                {col.title}
              </h4>
              <nav className="space-y-2">
                {col.links.map((link, idx) => {
                  const href = link.url.startsWith('http') ? link.url : `/${lang}${link.url}`;
                  return (
                    <Link
                      key={idx}
                      href={href}
                      className="block text-sm hover:text-slate-900 dark:hover:text-white transition-colors"
                      style={style.linkColor ? { color: style.linkColor } : {}}
                    >
                      {link.label}
                    </Link>
                  );
                })}
              </nav>
            </div>
          ))}
        </div>

        {/* Bottom Bar */}
        {(bottomBar?.show ?? true) && (
          <div
            className="border-t border-slate-200 dark:border-neutral-800 mt-8 pt-8 flex flex-col sm:flex-row items-center justify-between gap-4 text-sm"
            style={borderStyle}
          >
            <p className="text-slate-500 dark:text-neutral-400">{copyrightText}</p>

            {bottomBar?.showSocialLinks && (bottomBar.socialLinks || []).length > 0 && (
              <div className="flex items-center gap-3">
                {bottomBar.socialLinks.map((social, idx) => {
                  const Icon = SOCIAL_ICONS[social.platform];
                  return Icon ? (
                    <a
                      key={idx}
                      href={social.url}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="text-slate-400 hover:text-slate-700 dark:hover:text-white transition-colors"
                      aria-label={social.platform}
                    >
                      <Icon className="h-4 w-4" />
                    </a>
                  ) : null;
                })}
              </div>
            )}
          </div>
        )}
      </div>
    </footer>
  );
}
